using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN=35;
string s[100005],str;
int n,ans=inf,cnt[MAXN],len;
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;++i)
	{
		cin>>s[i];
	}
	int l=0,r=0,lengt=0;
	len=0;
	while(l<=r&&r<=n)
	{
		if(len<26)
		{
			++r;
			lengt+=s[r].size();
			if(r>n)break;
			for(int i=0;i<s[r].size();++i)
			{
				++cnt[int(s[r][i]-'a')];
				if(cnt[int(s[r][i]-'a')]==1)
				{
					++len;
				}
			}
		}
		else
		{
			ans=min(ans,lengt);
			lengt-=s[l].size();
			for(int i=0;i<s[l].size();++i)
			{
				--cnt[int(s[l][i]-'a')];
				if(cnt[int(s[l][i]-'a')]==0)
				{
					--len;
				}
			}
			++l;
		}
	}
	cout<<ans;

	return false;
}
